import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

type Debt = { name: string; balance: number; apr: number; min: number };

const FAQS = [
  { q: "What is debt consolidation?", a: "Debt consolidation combines multiple debts into one new loan or payment, often with the goal of lowering interest, simplifying payments, or both." },
  { q: "How do you calculate if debt consolidation saves money?", a: "Compare the total cost of your current debts with the total cost of the consolidation loan, including interest, fees, term length, and monthly payment." },
  { q: "What is a debt consolidation loan?", a: "A debt consolidation loan is a personal loan used to pay off several existing debts so you make one fixed payment instead." },
  { q: "Does debt consolidation hurt your credit?", a: "It can cause a short-term credit inquiry, but it may help over time if it lowers utilization and you make every payment on time." },
  { q: "What is the difference between debt consolidation and debt settlement?", a: "Consolidation repays debts through a new loan. Settlement tries to negotiate paying less than owed and can damage credit." },
];

const money = (value: number, digits = 0) => formatCurrencyValue(Number.isFinite(value) ? value : 0, { maximumFractionDigits: digits });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function loanPayment(balance: number, apr: number, months: number) {
  const r = apr / 100 / 12;
  if (r === 0) return balance / Math.max(1, months);
  return balance * r / (1 - Math.pow(1 + r, -months));
}

function payoffAtMinimum(debt: Debt) {
  let balance = debt.balance;
  let interestTotal = 0;
  let paidTotal = 0;
  for (let month = 1; month <= 1200 && balance > 0.01; month++) {
    const interest = balance * (debt.apr / 100 / 12);
    if (debt.min <= interest) return { months: Infinity, interestTotal: Infinity, paidTotal: Infinity };
    const paid = Math.min(debt.min, balance + interest);
    balance = Math.max(0, balance + interest - paid);
    interestTotal += interest;
    paidTotal += paid;
  }
  return { months: 0, interestTotal, paidTotal };
}

export default function DebtConsolidationCalculator() {
  useCurrencyVersion();
  const [debts, setDebts] = useState<Debt[]>([
    { name: "Credit Card", balance: 5000, apr: 22, min: 150 },
    { name: "Personal Loan", balance: 8000, apr: 13, min: 250 },
    { name: "Store Card", balance: 2500, apr: 28, min: 90 },
    { name: "Medical Bill", balance: 3000, apr: 8, min: 100 },
  ]);
  const [newRate, setNewRate] = useState(8);
  const [term, setTerm] = useState(5);
  const updateDebt = (index: number, key: keyof Debt, value: string | number) => setDebts((list) => list.map((debt, i) => i === index ? { ...debt, [key]: value } : debt));
  const addDebt = () => setDebts((list) => list.length >= 10 ? list : [...list, { name: `Debt ${list.length + 1}`, balance: 1000, apr: 18, min: 50 }]);
  const result = useMemo(() => {
    const totalBalance = debts.reduce((sum, debt) => sum + debt.balance, 0);
    const currentPayment = debts.reduce((sum, debt) => sum + debt.min, 0);
    const currentInterest = debts.reduce((sum, debt) => sum + payoffAtMinimum(debt).interestTotal, 0);
    const months = term * 12;
    const newPayment = loanPayment(totalBalance, newRate, months);
    const newInterest = newPayment * months - totalBalance;
    return { totalBalance, currentPayment, currentInterest, newPayment, newInterest, monthlySavings: currentPayment - newPayment, interestSavings: currentInterest - newInterest, totalSavings: (currentPayment * months) - (newPayment * months) };
  }, [debts, newRate, term]);
  const example = [
    { debt: "Credit Card", balance: 5000, apr: 22, min: 150 },
    { debt: "Personal Loan", balance: 8000, apr: 13, min: 250 },
    { debt: "Store Card", balance: 2500, apr: 28, min: 90 },
    { debt: "Medical Bill", balance: 3000, apr: 8, min: 100 },
  ];
  const exampleTotal = example.reduce((sum, row) => sum + row.balance, 0);
  const exampleAfter = loanPayment(exampleTotal, 8, 60);

  return (
    <>
      <SEOHead title="Free Debt Consolidation Calculator Online - See If Consolidating Saves You Money Instantly | CalcHive" description="Free online debt consolidation calculator. See if consolidating your debts saves money by comparing current total payments vs a single consolidation loan instantly. 100% free, no signup required." canonical="/debt-consolidation-calculator" keywords="free debt consolidation calculator, debt consolidation calculator online free, should I consolidate debt calculator free, debt consolidation savings calculator free, consolidation loan calculator free" category="Financial Calculators" breadcrumbName="Free Debt Consolidation Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Debt Consolidation Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Compare current debts against a single consolidation loan to estimate savings and monthly payment changes.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-3 mb-6">{debts.map((debt, index) => <div key={index} className="grid grid-cols-2 sm:grid-cols-4 gap-3 bg-accent/40 border border-border rounded-xl p-3"><input value={debt.name} onChange={(e) => updateDebt(index, "name", e.target.value)} className={inputClass} aria-label="Debt name" /><input type="number" value={debt.balance} onChange={(e) => updateDebt(index, "balance", Number(e.target.value))} className={inputClass} aria-label="Balance" /><input type="number" value={debt.apr} onChange={(e) => updateDebt(index, "apr", Number(e.target.value))} className={inputClass} aria-label="APR" /><input type="number" value={debt.min} onChange={(e) => updateDebt(index, "min", Number(e.target.value))} className={inputClass} aria-label="Minimum payment" /></div>)}</div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mb-8"><button type="button" onClick={addDebt} className="px-4 py-3 rounded-xl bg-primary text-primary-foreground font-bold">Add Debt</button><div><label className="text-sm font-semibold text-foreground block mb-2">Consolidation loan rate (%)</label><input type="number" value={newRate} onChange={(e) => setNewRate(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Loan term (years)</label><input type="number" value={term} onChange={(e) => setTerm(Number(e.target.value))} className={inputClass} /></div></div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">New Single Monthly Payment</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.newPayment)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Monthly savings</p><p className="text-lg font-extrabold text-foreground">{money(result.monthlySavings)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Interest savings</p><p className="text-lg font-extrabold text-foreground">{money(result.interestSavings)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total debt</p><p className="text-lg font-extrabold text-foreground">{money(result.totalBalance)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate If Debt Consolidation Saves You Money for Free</h2><p className="text-muted-foreground leading-relaxed">Compare your current total minimum payments and interest cost with the single payment and total interest on a consolidation loan.</p>
          <h2 className="text-2xl font-bold text-foreground">How Debt Consolidation Works and When It Makes Sense</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Debt Consolidation - Before vs After Example</caption><thead className="bg-muted/60"><tr>{["Debt", "Balance", "Current APR", "Current Min Payment", "After Consolidation at 8%"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{example.map((row) => <tr key={row.debt}><td className="py-2.5 px-3 font-semibold">{row.debt}</td><td className="py-2.5 px-3">{money(row.balance)}</td><td className="py-2.5 px-3">{row.apr}%</td><td className="py-2.5 px-3">{money(row.min)}</td><td className="py-2.5 px-3">{money(exampleAfter / example.length)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Debt Consolidation Comparison Tool for Everyone</h2><p className="text-muted-foreground leading-relaxed">A consolidation loan can reduce monthly payments when the new rate or term is better, but the full cost should be checked before moving balances.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/debt-consolidation-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


